import React, { useState } from 'react';
import jacketImg   from '../assets/images/jacket.png';
import shirtImg    from '../assets/images/shirt.png';
import menYarn     from '../assets/images/men yarn.png';
import skirtImg    from '../assets/images/women\'s party.png';
import casualImg   from '../assets/images/casual.png';
import watchesImg  from '../assets/images/watches.png';
import smartWatch  from '../assets/images/smartwatch.png';
import womensParty from '../assets/images/women\'s party.png';
import menWinter   from '../assets/images/men\'s winter.png';
import trekkingImg from '../assets/images/trekking.png';
import sportsImg   from '../assets/images/sports.png';
import betterBasic from '../assets/images/better basic.png';
import './NewProducts.css';

const products = [
  { id: 1,  img: jacketImg,   cat: 'JACKET',     name: "Men's Winter Leathers Jackets",       stars: 3, price: '48.00', old: '75.00', badge: '15%',  badgeType: 'discount' },
  { id: 2,  img: shirtImg,    cat: 'SHIRT',      name: 'Pure Garment Dyed Cotton Shirt',       stars: 3, price: '45.00', old: '56.00', badge: 'SALE', badgeType: 'sale'     },
  { id: 3,  img: menYarn,     cat: 'JACKET',     name: 'MEN Yarn Fleece Full Zip Jacket',      stars: 3, price: '58.00', old: '85.00', badge: null,   badgeType: null       },
  { id: 4,  img: skirtImg,    cat: 'SKIRT',      name: 'Black Floral Wrap Midi Skirt',         stars: 3, price: '25.00', old: '35.00', badge: 'NEW',  badgeType: 'new'      },
  { id: 5,  img: casualImg,   cat: 'CASUAL',     name: "Casual Men's Brown Shoes",             stars: 3, price: '58.00', old: '85.00', badge: null,   badgeType: null       },
  { id: 6,  img: watchesImg,  cat: 'WATCHES',    name: 'Pocket Watch Leather Pouch',           stars: 3, price: '70.00', old: '86.00', badge: 'SALE', badgeType: 'sale'     },
  { id: 7,  img: smartWatch,  cat: 'WATCHES',    name: 'Smart Watch Vital Plus',               stars: 3, price: '58.00', old: '65.00', badge: null,   badgeType: null       },
  { id: 8,  img: womensParty, cat: 'PARTY WEAR', name: "Women's Party Wear Shoes",             stars: 3, price: '58.00', old: '64.00', badge: 'SALE', badgeType: 'sale'     },
  { id: 9,  img: menWinter,   cat: 'JACKET',     name: "Men's Winter Leathers Jackets",        stars: 3, price: '58.00', old: '65.00', badge: null,   badgeType: null       },
  { id: 10, img: trekkingImg, cat: 'SPORTS',     name: 'Trekking & Running Shoes - Black',     stars: 4, price: '58.00', old: '64.00', badge: 'SALE', badgeType: 'sale'     },
  { id: 11, img: sportsImg,   cat: 'FORMAL',     name: "Men's Leather Formal Wear Shoes",      stars: 3, price: '58.00', old: '65.00', badge: null,   badgeType: null       },
  { id: 12, img: betterBasic, cat: 'SHORTS',     name: 'Better Basics French Terry Sweatshorts', stars: 3, price: '70.00', old: '86.00', badge: 'SALE', badgeType: 'sale'  },
];

function Stars({ count }) {
  return (
    <div className="np-stars">
      {[1,2,3,4,5].map((s) => (
        <span key={s} className={s <= count ? 'np-star filled' : 'np-star'}>★</span>
      ))}
    </div>
  );
}

export default function NewProducts() {
  const [hovered, setHovered] = useState(null);

  return (
    <section className="np-section">
      <h2 className="np-heading">New Products</h2>

      <div className="np-grid">
        {products.map((p) => (
          <div
            key={p.id}
            className="np-card"
            onMouseEnter={() => setHovered(p.id)}
            onMouseLeave={() => setHovered(null)}
          >
            {/* Badge */}
            {p.badge && (
              <span className={`np-badge np-badge-${p.badgeType}`}>{p.badge}</span>
            )}

            {/* Image */}
            <div className="np-img-wrap">
              <img src={p.img} alt={p.name} className="np-img" />

              {/* Hover action icons */}
              {hovered === p.id && (
                <div className="np-actions">
                  <button className="np-action-btn" aria-label="Wishlist">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/></svg>
                  </button>
                  <button className="np-action-btn" aria-label="Quick view">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
                  </button>
                  <button className="np-action-btn" aria-label="Compare">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="17 1 21 5 17 9"/><path d="M3 11V9a4 4 0 0 1 4-4h14"/><polyline points="7 23 3 19 7 15"/><path d="M21 13v2a4 4 0 0 1-4 4H3"/></svg>
                  </button>
                  <button className="np-action-btn" aria-label="Add to cart">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4z"/><line x1="3" y1="6" x2="21" y2="6"/><path d="M16 10a4 4 0 0 1-8 0"/></svg>
                  </button>
                </div>
              )}
            </div>

            {/* Info */}
            <div className="np-info">
              <p className="np-cat">{p.cat}</p>
              <p className="np-name">{p.name}</p>
              <Stars count={p.stars} />
              <div className="np-price-row">
                <span className="np-price">${p.price}</span>
                <span className="np-old">${p.old}</span>
              </div>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}
